var COURSE_PL_KO = [{day: 1, title: `Pierwsze powitania i uprzejmość`, title_native: `첫 인사와 예절`, focus: `Nauczysz się podstawowych powitań używanych w Seulu, Busanie i innych miastach Korei Południowej. Ten dzień pomoże ci rozpocząć rozmowę w sklepie, hotelu lub na ulicy z odpowiednim poziomem uprzejmości.`, vocab: [{ko: `안녕하세요`, pl: `dzień dobry / cześć`, ipa: `an-njong-ha-se-jo`},{ko: `감사합니다`, pl: `dziękuję`, ipa: `kam-sa-ham-ni-da`},{ko: `네`, pl: `tak`, ipa: `ne`},{ko: `아니요`, pl: `nie`, ipa: `a-ni-jo`},{ko: `죄송합니다`, pl: `przepraszam`, ipa: `cze-song-ham-ni-da`},{ko: `괜찮아요`, pl: `w porządku`, ipa: `kwan-czan-a-jo`},{ko: `저`, pl: `ja / mnie`, ipa: `czo`},{ko: `당신`, pl: `ty / pan / pani`, ipa: `tang-sin`},{ko: `이름`, pl: `imię`, ipa: `i-rym`},{ko: `한국`, pl: `Korea`, ipa: `han-guk`}], phrases: [{ko: `안녕하세요.`, pl: `Dzień dobry.`, ipa: `an-njong-ha-se-jo`},{ko: `감사합니다.`, pl: `Dziękuję.`, ipa: `kam-sa-ham-ni-da`},{ko: `죄송합니다.`, pl: `Przepraszam.`, ipa: `cze-song-ham-ni-da`},{ko: `괜찮아요.`, pl: `W porządku.`, ipa: `kwan-czan-a-jo`},{ko: `제 이름은 안나예요.`, pl: `Mam na imię Anna.`, ipa: `cze i-ry-myn an-na-je-jo`},{ko: `만나서 반가워요.`, pl: `Miło mi cię poznać.`, ipa: `man-na-so pan-ga-wo-jo`}], grammar: `Koreański ma różne poziomy grzeczności, a podróżnik powinien zaczynać od form uprzejmych. Końcówka -요 często sprawia, że zdanie brzmi uprzejmie, ale nadal naturalnie w codziennych sytuacjach. 안녕하세요 i 감사합니다 są bezpieczne w hotelu, kawiarni, metrze i przy rozmowie z nieznajomymi.`, practice: [`Powiedz po koreańsku „Dzień dobry” do recepcjonisty w hotelu.`,`Przećwicz przedstawienie się: „Mam na imię...” z własnym imieniem.`,`Wybierz właściwą odpowiedź na podziękowanie: 네, 아니요 czy 괜찮아요.`,`Powiedz „Przepraszam” tak, jakbyś przypadkowo kogoś potrącił w metrze.`,`Ułóż krótką wymianę: powitanie, imię, „miło mi cię poznać”.`]},{day: 2, title: `Hangul i prosta wymowa`, title_native: `한글과 쉬운 발음`, focus: `Poznasz podstawy koreańskiego pisma hangul, przydatne przy czytaniu nazw stacji metra, szyldów i menu w Seulu. Nie musisz opanować wszystkiego od razu, ale nauczysz się rozpoznawać kilka ważnych dźwięków.`, vocab: [{ko: `한글`, pl: `hangul, alfabet koreański`, ipa: `han-gyl`},{ko: `글자`, pl: `litera / znak`, ipa: `kyl-cza`},{ko: `소리`, pl: `dźwięk`, ipa: `so-ri`},{ko: `모음`, pl: `samogłoska`, ipa: `mo-ym`},{ko: `자음`, pl: `spółgłoska`, ipa: `cza-ym`},{ko: `가`, pl: `sylaba „ga/ka”`, ipa: `ga`},{ko: `나`, pl: `sylaba „na”`, ipa: `na`},{ko: `다`, pl: `sylaba „da/ta”`, ipa: `da`},{ko: `마`, pl: `sylaba „ma”`, ipa: `ma`},{ko: `서울`, pl: `Seul`, ipa: `so-ul`}], phrases: [{ko: `이거 읽어 주세요.`, pl: `Proszę to przeczytać.`, ipa: `i-go il-go dżu-se-jo`},{ko: `한국어를 조금 읽어요.`, pl: `Trochę czytam po koreańsku.`, ipa: `han-gu-go-ryl czo-gym il-go-jo`},{ko: `천천히 말해 주세요.`, pl: `Proszę mówić powoli.`, ipa: `czon-czo-ni mal-he dżu-se-jo`},{ko: `다시 말해 주세요.`, pl: `Proszę powiedzieć jeszcze raz.`, ipa: `ta-si mal-he dżu-se-jo`},{ko: `이건 뭐예요?`, pl: `Co to jest?`, ipa: `i-gon mwo-je-jo`},{ko: `서울역이에요.`, pl: `To jest stacja Seul.`, ipa: `so-ul-jog-i-e-jo`}], grammar: `Hangul składa sylaby w małe bloki, na przykład 한, 국, 어. W podróży ważniejsze jest rozpoznawanie słów niż perfekcyjne pisanie. Gdy nie rozumiesz wymowy, użyj 천천히 말해 주세요 albo 다시 말해 주세요 — to bardzo praktyczne zdania.`, practice: [`Przeczytaj na głos sylaby 가, 나, 다, 마.`,`Powiedz po koreańsku „Proszę mówić powoli”.`,`Zapytaj „Co to jest?” wskazując na napis w menu.`,`Napisz własną notatkę: które koreańskie dźwięki są dla ciebie najłatwiejsze.`,`Połącz słowo 서울 z polskim znaczeniem.`]},{day: 3, title: `Liczby od 1 do 10`, title_native: `숫자 1부터 10까지`, focus: `Nauczysz się podstawowych liczb, które przydadzą się przy kupowaniu kawy, biletów i przekąsek. W Korei istnieją dwa systemy liczbowe, ale dziś skupiamy się na najprostszych formach użytecznych dla turysty.`, vocab: [{ko: `하나`, pl: `jeden`, ipa: `ha-na`},{ko: `둘`, pl: `dwa`, ipa: `dul`},{ko: `셋`, pl: `trzy`, ipa: `set`},{ko: `넷`, pl: `cztery`, ipa: `net`},{ko: `다섯`, pl: `pięć`, ipa: `ta-sot`},{ko: `여섯`, pl: `sześć`, ipa: `jo-sot`},{ko: `일곱`, pl: `siedem`, ipa: `il-gop`},{ko: `여덟`, pl: `osiem`, ipa: `jo-dol`},{ko: `아홉`, pl: `dziewięć`, ipa: `a-hop`},{ko: `열`, pl: `dziesięć`, ipa: `jol`}], phrases: [{ko: `하나 주세요.`, pl: `Proszę jedno.`, ipa: `ha-na dżu-se-jo`},{ko: `두 개 주세요.`, pl: `Proszę dwie sztuki.`, ipa: `du ge dżu-se-jo`},{ko: `세 명이에요.`, pl: `Jesteśmy trzy osoby.`, ipa: `se mjong-i-e-jo`},{ko: `몇 개예요?`, pl: `Ile sztuk?`, ipa: `mjot ge-je-jo`},{ko: `몇 명이에요?`, pl: `Ile osób?`, ipa: `mjot mjong-i-e-jo`},{ko: `하나 더 주세요.`, pl: `Proszę jeszcze jedno.`, ipa: `ha-na do dżu-se-jo`}], grammar: `Przy rzeczach używa się licznika 개, a przy osobach 명. Liczby 하나, 둘, 셋, 넷 często zmieniają się przed licznikiem: 한 개, 두 개, 세 개, 네 개. W kawiarni lub sklepie najprostsza konstrukcja to liczba + 개 + 주세요.`, practice: [`Zamów jedną kawę, używając 하나 주세요.`,`Powiedz, że są trzy osoby przy stoliku.`,`Przećwicz pytanie „Ile sztuk?”.`,`Policz po koreańsku od 1 do 10.`,`Ułóż zdanie: „Proszę jeszcze jedno”.`]},{day: 4, title: `Przedstawianie się i kraj pochodzenia`, title_native: `자기소개와 출신 나라`, focus: `Nauczysz się mówić, skąd jesteś i jak się nazywasz. To przyda się przy rozmowie z lokalną osobą w hostelu, na wycieczce lub przy wspólnym stoliku w kawiarni.`, vocab: [{ko: `폴란드`, pl: `Polska`, ipa: `pol-lan-dy`},{ko: `사람`, pl: `osoba / człowiek`, ipa: `sa-ram`},{ko: `여행자`, pl: `podróżnik`, ipa: `jo-heng-dża`},{ko: `친구`, pl: `przyjaciel`, ipa: `czin-gu`},{ko: `학생`, pl: `student`, ipa: `hak-seng`},{ko: `회사원`, pl: `pracownik biurowy`, ipa: `hwe-sa-won`},{ko: `저는`, pl: `ja jestem / jeśli chodzi o mnie`, ipa: `czo-nyn`},{ko: `입니다`, pl: `jestem / jest, forma formalna`, ipa: `im-ni-da`},{ko: `이에요`, pl: `jest, forma uprzejma po spółgłosce`, ipa: `i-e-jo`},{ko: `예요`, pl: `jest, forma uprzejma po samogłosce`, ipa: `je-jo`}], phrases: [{ko: `저는 폴란드 사람이에요.`, pl: `Jestem z Polski.`, ipa: `czo-nyn pol-lan-dy sa-ra-mi-e-jo`},{ko: `저는 여행자예요.`, pl: `Jestem podróżnikiem.`, ipa: `czo-nyn jo-heng-dża-je-jo`},{ko: `제 이름은 마렉이에요.`, pl: `Mam na imię Marek.`, ipa: `cze i-ry-myn ma-re-gi-e-jo`},{ko: `저는 학생이에요.`, pl: `Jestem studentem.`, ipa: `czo-nyn hak-seng-i-e-jo`},{ko: `당신은 어디에서 왔어요?`, pl: `Skąd jesteś?`, ipa: `tang-si-nyn o-di-e-so wa-so-jo`},{ko: `반가워요.`, pl: `Miło mi.`, ipa: `pan-ga-wo-jo`}], grammar: `저는 oznacza „jeśli chodzi o mnie” i często rozpoczyna zdanie o sobie. Po rzeczownikach używa się 이에요 albo 예요: 학생이에요, 여행자예요. W rozmowie z nieznajomymi lepiej unikać zbyt bezpośredniego 당신 i częściej pytać prościej: 어디에서 왔어요?`, practice: [`Powiedz po koreańsku, że jesteś z Polski.`,`Przedstaw się własnym imieniem.`,`Powiedz, że jesteś podróżnikiem.`,`Zapytaj drugą osobę, skąd jest.`,`Stwórz mini-dialog: powitanie, imię, kraj, „miło mi”.`]},{day: 5, title: `Podstawowe pytania`, title_native: `기본 질문`, focus: `Dziś nauczysz się zadawać proste pytania, które są niezbędne podczas podróży po Korei. Użyjesz ich przy szukaniu toalety, wejścia, ceny lub stacji metra.`, vocab: [{ko: `어디`, pl: `gdzie`, ipa: `o-di`},{ko: `뭐`, pl: `co`, ipa: `mwo`},{ko: `누구`, pl: `kto`, ipa: `nu-gu`},{ko: `언제`, pl: `kiedy`, ipa: `on-dże`},{ko: `왜`, pl: `dlaczego`, ipa: `we`},{ko: `어떻게`, pl: `jak`, ipa: `o-tto-ke`},{ko: `화장실`, pl: `toaleta`, ipa: `hwa-dżang-sil`},{ko: `입구`, pl: `wejście`, ipa: `ip-gu`},{ko: `출구`, pl: `wyjście`, ipa: `czul-gu`},{ko: `가격`, pl: `cena`, ipa: `ka-gjok`}], phrases: [{ko: `화장실은 어디예요?`, pl: `Gdzie jest toaleta?`, ipa: `hwa-dżang-si-lyn o-di-je-jo`},{ko: `이건 뭐예요?`, pl: `Co to jest?`, ipa: `i-gon mwo-je-jo`},{ko: `가격이 얼마예요?`, pl: `Ile to kosztuje?`, ipa: `ka-gjo-gi ol-ma-je-jo`},{ko: `출구는 어디예요?`, pl: `Gdzie jest wyjście?`, ipa: `czul-gu-nyn o-di-je-jo`},{ko: `언제 열어요?`, pl: `Kiedy otwieracie?`, ipa: `on-dże jo-ro-jo`},{ko: `어떻게 가요?`, pl: `Jak tam dojść?`, ipa: `o-tto-ke ka-jo`}], grammar: `W koreańskim pytanie często ma taką samą kolejność jak zdanie oznajmujące, a intonacja i słowo pytające pokazują, że pytasz. 어디예요? znaczy „gdzie jest?”, a 뭐예요? znaczy „co to jest?”. Rzeczownik + 은/는 pomaga wskazać temat pytania: 화장실은 어디예요?`, practice: [`Zapytaj o toaletę w centrum handlowym w Seulu.`,`Zapytaj o cenę pamiątki.`,`Powiedz „Co to jest?” wskazując danie w menu.`,`Zapytaj, gdzie jest wyjście ze stacji.`,`Przećwicz trzy pytania z 어디, 뭐 i 언제.`]},{day: 6, title: `Prośby i uprzejme zamawianie`, title_native: `부탁과 정중한 주문`, focus: `Nauczysz się używać 주세요, czyli jednego z najważniejszych słów dla podróżnika. Przyda się w kawiarni w Hongdae, na targu w Busanie i przy kupowaniu biletu.`, vocab: [{ko: `주세요`, pl: `proszę dać`, ipa: `dżu-se-jo`},{ko: `물`, pl: `woda`, ipa: `mul`},{ko: `커피`, pl: `kawa`, ipa: `ko-pi`},{ko: `차`, pl: `herbata`, ipa: `cza`},{ko: `메뉴`, pl: `menu`, ipa: `me-niu`},{ko: `영수증`, pl: `paragon`, ipa: `jong-su-dżyng`},{ko: `봉투`, pl: `torba / reklamówka`, ipa: `pong-tu`},{ko: `티켓`, pl: `bilet`, ipa: `ti-ket`},{ko: `자리`, pl: `miejsce / siedzenie`, ipa: `cza-ri`},{ko: `도움`, pl: `pomoc`, ipa: `to-um`}], phrases: [{ko: `물 주세요.`, pl: `Proszę wodę.`, ipa: `mul dżu-se-jo`},{ko: `메뉴 주세요.`, pl: `Proszę menu.`, ipa: `me-niu dżu-se-jo`},{ko: `영수증 주세요.`, pl: `Proszę paragon.`, ipa: `jong-su-dżyng dżu-se-jo`},{ko: `도와주세요.`, pl: `Proszę pomóc.`, ipa: `to-wa-dżu-se-jo`},{ko: `티켓 하나 주세요.`, pl: `Proszę jeden bilet.`, ipa: `ti-ket ha-na dżu-se-jo`},{ko: `봉투 주세요.`, pl: `Proszę torbę.`, ipa: `pong-tu dżu-se-jo`}], grammar: `주세요 dosłownie oznacza „proszę dać” lub „proszę zrobić dla mnie”. Możesz dodać rzeczownik przed 주세요, aby poprosić o konkretną rzecz: 물 주세요. W sytuacjach usługowych to bardzo naturalna i uprzejma forma.`, practice: [`Poproś o wodę w restauracji.`,`Poproś o menu w kawiarni.`,`Kup jeden bilet, używając 티켓 하나 주세요.`,`Powiedz „Proszę pomóc” w punkcie informacji turystycznej.`,`Ułóż trzy własne prośby z 주세요.`]},{day: 7, title: `Dni tygodnia i czas`, title_native: `요일과 시간`, focus: `Dziś nauczysz się mówić o dniach tygodnia i prostym czasie. Przyda się to przy rezerwacji wejścia do muzeum, sprawdzaniu godzin otwarcia i umawianiu spotkania.`, vocab: [{ko: `오늘`, pl: `dzisiaj`, ipa: `o-nyl`},{ko: `내일`, pl: `jutro`, ipa: `ne-il`},{ko: `어제`, pl: `wczoraj`, ipa: `o-dże`},{ko: `월요일`, pl: `poniedziałek`, ipa: `wo-ryo-il`},{ko: `화요일`, pl: `wtorek`, ipa: `hwa-yo-il`},{ko: `수요일`, pl: `środa`, ipa: `su-yo-il`},{ko: `목요일`, pl: `czwartek`, ipa: `mo-gyo-il`},{ko: `금요일`, pl: `piątek`, ipa: `ky-myo-il`},{ko: `토요일`, pl: `sobota`, ipa: `to-yo-il`},{ko: `일요일`, pl: `niedziela`, ipa: `i-ryo-il`}], phrases: [{ko: `오늘 열어요?`, pl: `Czy dzisiaj jest otwarte?`, ipa: `o-nyl jo-ro-jo`},{ko: `내일 가요.`, pl: `Idę jutro.`, ipa: `ne-il ka-jo`},{ko: `몇 시예요?`, pl: `Która godzina?`, ipa: `mjot si-je-jo`},{ko: `월요일에 만나요.`, pl: `Spotkajmy się w poniedziałek.`, ipa: `wo-ryo-i-re man-na-jo`},{ko: `금요일에 예약했어요.`, pl: `Mam rezerwację na piątek.`, ipa: `ky-myo-i-re je-ja-khe-so-jo`},{ko: `지금 가요.`, pl: `Idę teraz.`, ipa: `ci-gym ka-jo`}], grammar: `Partykuła 에 po dniu tygodnia oznacza „w” lub „na”: 월요일에 to „w poniedziałek”. 몇 시예요? pyta o godzinę. W podróży często wystarczy połączyć dzień z czasownikiem, na przykład 내일 가요 — „idę jutro”.`, practice: [`Powiedz, że idziesz jutro.`,`Zapytaj, czy muzeum jest dziś otwarte.`,`Powiedz „Spotkajmy się w piątek”.`,`Zapytaj o godzinę.`,`Wymień po koreańsku trzy dni tygodnia, które zapamiętałeś.`]},{day: 8, title: `W kawiarni`, title_native: `카페에서`, focus: `Nauczysz się zamawiać kawę i proste napoje w koreańskiej kawiarni. Scena pasuje do kawiarni w Seongsu, Hongdae albo przy plaży Haeundae w Busanie.`, vocab: [{ko: `카페`, pl: `kawiarnia`, ipa: `ka-pe`},{ko: `아메리카노`, pl: `americano`, ipa: `a-me-ri-ka-no`},{ko: `라떼`, pl: `latte`, ipa: `la-tte`},{ko: `아이스`, pl: `mrożony / z lodem`, ipa: `a-i-sy`},{ko: `뜨거운`, pl: `gorący`, ipa: `tty-go-un`},{ko: `설탕`, pl: `cukier`, ipa: `sol-tang`},{ko: `우유`, pl: `mleko`, ipa: `u-ju`},{ko: `컵`, pl: `kubek`, ipa: `kop`},{ko: `포장`, pl: `na wynos`, ipa: `po-dżang`},{ko: `매장`, pl: `na miejscu`, ipa: `me-dżang`}], phrases: [{ko: `아이스 아메리카노 주세요.`, pl: `Poproszę mrożone americano.`, ipa: `a-i-sy a-me-ri-ka-no dżu-se-jo`},{ko: `뜨거운 라떼 주세요.`, pl: `Poproszę gorące latte.`, ipa: `tty-go-un la-tte dżu-se-jo`},{ko: `포장해 주세요.`, pl: `Proszę na wynos.`, ipa: `po-dżang-he dżu-se-jo`},{ko: `매장에서 마실게요.`, pl: `Wypiję na miejscu.`, ipa: `me-dżang-e-so ma-sil-ge-jo`},{ko: `설탕 빼 주세요.`, pl: `Proszę bez cukru.`, ipa: `sol-tang ppe dżu-se-jo`},{ko: `우유 조금 주세요.`, pl: `Proszę trochę mleka.`, ipa: `u-ju czo-gym dżu-se-jo`}], grammar: `W koreańskich kawiarniach często usłyszysz pytanie 포장이세요? czyli „na wynos?”. Możesz odpowiedzieć 포장해 주세요 albo 매장에서 마실게요. 빼 주세요 oznacza „proszę bez” lub „proszę wyjąć”, bardzo przydatne przy cukrze, lodzie lub składnikach.`, practice: [`Zamów mrożone americano.`,`Powiedz, że chcesz wypić na miejscu.`,`Poproś o latte na wynos.`,`Powiedz „bez cukru”.`,`Ułóż dialog z baristą w trzech krótkich liniach.`]},{day: 9, title: `Jedzenie i proste menu`, title_native: `음식과 쉬운 메뉴`, focus: `Dziś nauczysz się rozpoznawać popularne koreańskie jedzenie i pytać o dania w menu. Przyda się to w restauracji z kimchi jjigae, bibimbapem albo bulgogi.`, vocab: [{ko: `음식`, pl: `jedzenie`, ipa: `ym-sik`},{ko: `밥`, pl: `ryż / posiłek`, ipa: `pap`},{ko: `김치`, pl: `kimchi`, ipa: `kim-czi`},{ko: `비빔밥`, pl: `bibimbap`, ipa: `pi-bim-bap`},{ko: `불고기`, pl: `bulgogi`, ipa: `pul-go-gi`},{ko: `찌개`, pl: `gulasz / zupa`, ipa: `cci-ge`},{ko: `국`, pl: `zupa`, ipa: `guk`},{ko: `고기`, pl: `mięso`, ipa: `ko-gi`},{ko: `채소`, pl: `warzywa`, ipa: `cze-so`},{ko: `반찬`, pl: `przystawki`, ipa: `pan-czan`}], phrases: [{ko: `이거 맛있어요?`, pl: `Czy to jest smaczne?`, ipa: `i-go ma-si-so-jo`},{ko: `추천해 주세요.`, pl: `Proszę coś polecić.`, ipa: `czu-czon-he dżu-se-jo`},{ko: `비빔밥 주세요.`, pl: `Poproszę bibimbap.`, ipa: `pi-bim-bap dżu-se-jo`},{ko: `고기 있어요?`, pl: `Czy jest mięso?`, ipa: `ko-gi i-so-jo`},{ko: `채소만 있어요?`, pl: `Czy są tylko warzywa?`, ipa: `cze-so-man i-so-jo`},{ko: `반찬 더 주세요.`, pl: `Proszę więcej przystawek.`, ipa: `pan-czan do dżu-se-jo`}], grammar: `있어요 oznacza „jest / są / mam”, a 없어요 oznacza „nie ma / nie mam”. W restauracji pytanie 고기 있어요? pomaga sprawdzić, czy danie ma mięso. Słowo 만 oznacza „tylko”, na przykład 채소만 — „tylko warzywa”.`, practice: [`Zapytaj, czy danie ma mięso.`,`Poproś kelnera o rekomendację.`,`Zamów bibimbap.`,`Powiedz „Czy to jest smaczne?”.`,`Poproś o więcej przystawek.`]},{day: 10, title: `Smaki i preferencje`, title_native: `맛과 취향`, focus: `Nauczysz się mówić, czy jedzenie jest ostre, słodkie, słone lub dobre. To szczególnie ważne w Korei, gdzie wiele dań może być pikantnych.`, vocab: [{ko: `맛`, pl: `smak`, ipa: `mat`},{ko: `맛있어요`, pl: `smaczne`, ipa: `ma-si-so-jo`},{ko: `맛없어요`, pl: `niesmaczne`, ipa: `ma-do-psso-jo`},{ko: `매워요`, pl: `ostre`, ipa: `me-wo-jo`},{ko: `달아요`, pl: `słodkie`, ipa: `ta-ra-jo`},{ko: `짜요`, pl: `słone`, ipa: `ccha-jo`},{ko: `싱거워요`, pl: `mdłe / mało słone`, ipa: `sing-go-wo-jo`},{ko: `뜨거워요`, pl: `gorące`, ipa: `tty-go-wo-jo`},{ko: `차가워요`, pl: `zimne`, ipa: `cza-ga-wo-jo`},{ko: `괜찮아요`, pl: `w porządku`, ipa: `kwan-czan-a-jo`}], phrases: [{ko: `너무 매워요.`, pl: `To jest za ostre.`, ipa: `no-mu me-wo-jo`},{ko: `조금 매워요.`, pl: `To jest trochę ostre.`, ipa: `czo-gym me-wo-jo`},{ko: `안 맵게 해 주세요.`, pl: `Proszę, żeby nie było ostre.`, ipa: `an mep-ge he dżu-se-jo`},{ko: `정말 맛있어요.`, pl: `Naprawdę smaczne.`, ipa: `czong-mal ma-si-so-jo`},{ko: `조금 달아요.`, pl: `To jest trochę słodkie.`, ipa: `czo-gym ta-ra-jo`},{ko: `물 좀 주세요.`, pl: `Proszę trochę wody.`, ipa: `mul czom dżu-se-jo`}], grammar: `너무 oznacza „za bardzo” albo „bardzo”, a 조금 znaczy „trochę”. W restauracji 안 맵게 해 주세요 jest bardzo praktyczne, jeśli nie lubisz pikantnego jedzenia. 맵다 to „być ostrym”, ale w uprzejmej mowie mówimy 매워요.`, practice: [`Powiedz, że danie jest za ostre.`,`Poproś, aby danie nie było ostre.`,`Powiedz, że coś jest naprawdę smaczne.`,`Zapytaj o wodę po zjedzeniu ostrego kimchi.`,`Opisz po koreańsku trzy smaki: słodkie, słone, ostre.`]},{day: 11, title: `W restauracji`, title_native: `식당에서`, focus: `Połączysz słowa z poprzednich dni i przećwiczysz pełną sytuację w restauracji. Nauczysz się prosić o stolik, menu, danie i rachunek.`, vocab: [{ko: `식당`, pl: `restauracja`, ipa: `sik-tang`},{ko: `예약`, pl: `rezerwacja`, ipa: `je-jak`},{ko: `자리`, pl: `stolik / miejsce`, ipa: `cza-ri`},{ko: `메뉴판`, pl: `karta menu`, ipa: `me-niu-pan`},{ko: `주문`, pl: `zamówienie`, ipa: `czu-mun`},{ko: `계산`, pl: `rachunek / płatność`, ipa: `kye-san`},{ko: `카드`, pl: `karta`, ipa: `ka-dy`},{ko: `현금`, pl: `gotówka`, ipa: `hjon-gym`},{ko: `물컵`, pl: `szklanka na wodę`, ipa: `mul-kop`},{ko: `젓가락`, pl: `pałeczki`, ipa: `czot-ga-rak`}], phrases: [{ko: `두 명이에요.`, pl: `Jesteśmy dwie osoby.`, ipa: `du mjong-i-e-jo`},{ko: `예약했어요.`, pl: `Mam rezerwację.`, ipa: `je-ja-khe-so-jo`},{ko: `메뉴판 주세요.`, pl: `Proszę kartę menu.`, ipa: `me-niu-pan dżu-se-jo`},{ko: `주문할게요.`, pl: `Złożę zamówienie.`, ipa: `czu-mun-hal-ge-jo`},{ko: `계산해 주세요.`, pl: `Proszę rachunek.`, ipa: `kye-san-he dżu-se-jo`},{ko: `카드로 할게요.`, pl: `Zapłacę kartą.`, ipa: `ka-dy-ro hal-ge-jo`}], grammar: `-로 po rzeczowniku oznacza „za pomocą” lub „w formie”, na przykład 카드로 — kartą. 할게요 oznacza „zrobię / wybiorę”, często używane przy zamawianiu: 이걸로 할게요 — „wezmę to”. W restauracji 계산해 주세요 jest naturalnym sposobem poproszenia o rachunek.`, practice: [`Powiedz, że są dwie osoby.`,`Powiedz, że masz rezerwację.`,`Poproś o menu.`,`Zamów danie, używając 주문할게요.`,`Poproś o rachunek i powiedz, że płacisz kartą.`]},{day: 12, title: `Kierunki i miejsca w mieście`, title_native: `방향과 도시 장소`, focus: `Nauczysz się pytać o drogę do miejsc takich jak stacja metra, hotel, bankomat i apteka. To bardzo praktyczny dzień dla spacerów po Myeongdong, Insadong lub Gangnam.`, vocab: [{ko: `역`, pl: `stacja`, ipa: `jog`},{ko: `지하철`, pl: `metro`, ipa: `czi-ha-czol`},{ko: `버스 정류장`, pl: `przystanek autobusowy`, ipa: `po-sy czong-nyu-dżang`},{ko: `호텔`, pl: `hotel`, ipa: `ho-tel`},{ko: `은행`, pl: `bank`, ipa: `yn-heng`},{ko: `ATM`, pl: `bankomat`, ipa: `e-i-ti-em`},{ko: `약국`, pl: `apteka`, ipa: `jak-guk`},{ko: `병원`, pl: `szpital`, ipa: `pjong-won`},{ko: `오른쪽`, pl: `prawa strona`, ipa: `o-ryn-ccok`},{ko: `왼쪽`, pl: `lewa strona`, ipa: `wen-ccok`}], phrases: [{ko: `지하철역은 어디예요?`, pl: `Gdzie jest stacja metra?`, ipa: `czi-ha-czol-jo-gyn o-di-je-jo`},{ko: `오른쪽으로 가세요.`, pl: `Proszę iść w prawo.`, ipa: `o-ryn-cco-gy-ro ka-se-jo`},{ko: `왼쪽으로 가세요.`, pl: `Proszę iść w lewo.`, ipa: `wen-cco-gy-ro ka-se-jo`},{ko: `곧장 가세요.`, pl: `Proszę iść prosto.`, ipa: `kot-czang ka-se-jo`},{ko: `여기에서 멀어요?`, pl: `Czy to daleko stąd?`, ipa: `jo-gi-e-so mo-ro-jo`},{ko: `걸어서 갈 수 있어요?`, pl: `Czy można dojść pieszo?`, ipa: `ko-ro-so kal su i-so-jo`}], grammar: `-으로 / -로 może oznaczać kierunek: 오른쪽으로, 왼쪽으로. 가세요 to uprzejme „proszę iść”. 갈 수 있어요 oznacza „można pójść / mogę pójść”, bardzo przydatne w pytaniu 걸어서 갈 수 있어요?`, practice: [`Zapytaj o stację metra.`,`Powiedz komuś: „Proszę iść prosto”.`,`Zapytaj, czy można dojść pieszo.`,`Zapytaj, czy apteka jest daleko.`,`Narysuj prostą trasę i opisz ją po koreańsku trzema zdaniami.`]},{day: 13, title: `Metro i bilety`, title_native: `지하철과 표`, focus: `Nauczysz się słów przydatnych w koreańskim metrze, zwłaszcza w Seulu i Busanie. Przećwiczysz kupowanie biletu, pytanie o linię i kierunek.`, vocab: [{ko: `표`, pl: `bilet`, ipa: `pjo`},{ko: `교통카드`, pl: `karta transportowa`, ipa: `kyo-tong-ka-dy`},{ko: `노선`, pl: `linia / trasa`, ipa: `no-son`},{ko: `호선`, pl: `linia metra numer`, ipa: `ho-son`},{ko: `갈아타다`, pl: `przesiadać się`, ipa: `ka-ra-ta-da`},{ko: `출발`, pl: `odjazd / start`, ipa: `czul-bal`},{ko: `도착`, pl: `przyjazd`, ipa: `to-czak`},{ko: `방향`, pl: `kierunek`, ipa: `pang-hjang`},{ko: `플랫폼`, pl: `peron`, ipa: `pyl-let-pom`},{ko: `충전`, pl: `doładowanie`, ipa: `czung-dżon`}], phrases: [{ko: `교통카드 충전해 주세요.`, pl: `Proszę doładować kartę transportową.`, ipa: `kyo-tong-ka-dy czung-dżon-he dżu-se-jo`},{ko: `이 노선 맞아요?`, pl: `Czy to właściwa linia?`, ipa: `i no-son ma-dża-jo`},{ko: `몇 호선이에요?`, pl: `Która to linia metra?`, ipa: `mjot ho-so-ni-e-jo`},{ko: `어디에서 갈아타요?`, pl: `Gdzie się przesiadam?`, ipa: `o-di-e-so ka-ra-ta-jo`},{ko: `강남역 가요?`, pl: `Czy to jedzie do stacji Gangnam?`, ipa: `kang-nam-jok ka-jo`},{ko: `플랫폼은 어디예요?`, pl: `Gdzie jest peron?`, ipa: `pyl-let-po-myn o-di-je-jo`}], grammar: `맞아요? oznacza „czy to się zgadza?” albo „czy to właściwe?”. W metrze możesz wskazać mapę i zapytać 이 노선 맞아요? Nazwy stacji często łączą się z 역, na przykład 강남역, 서울역, 홍대입구역.`, practice: [`Zapytaj, czy dana linia jedzie do Gangnam.`,`Poproś o doładowanie karty transportowej.`,`Zapytaj, gdzie jest peron.`,`Zapytaj, gdzie się przesiąść.`,`Ułóż mini-dialog przy automacie biletowym.`]},{day: 14, title: `Taksówka i aplikacje przejazdowe`, title_native: `택시와 차량 앱`, focus: `Nauczysz się mówić kierowcy, dokąd chcesz jechać i jak poprosić o zatrzymanie. Przyda się to w taksówce z lotniska Incheon, na krótkiej trasie w Seulu lub późnym wieczorem w Busanie.`, vocab: [{ko: `택시`, pl: `taksówka`, ipa: `tek-si`},{ko: `기사님`, pl: `pan/pani kierowca`, ipa: `ki-sa-nim`},{ko: `공항`, pl: `lotnisko`, ipa: `kong-hang`},{ko: `주소`, pl: `adres`, ipa: `czu-so`},{ko: `여기`, pl: `tutaj`, ipa: `jo-gi`},{ko: `저기`, pl: `tam`, ipa: `czo-gi`},{ko: `도착했어요`, pl: `dotarliśmy`, ipa: `to-cza-ke-so-jo`},{ko: `세워 주세요`, pl: `proszę się zatrzymać`, ipa: `se-wo dżu-se-jo`},{ko: `천천히`, pl: `powoli`, ipa: `czon-czo-ni`},{ko: `빨리`, pl: `szybko`, ipa: `ppalli`}], phrases: [{ko: `이 주소로 가 주세요.`, pl: `Proszę jechać pod ten adres.`, ipa: `i czu-so-ro ka dżu-se-jo`},{ko: `공항으로 가 주세요.`, pl: `Proszę jechać na lotnisko.`, ipa: `kong-hang-y-ro ka dżu-se-jo`},{ko: `여기서 세워 주세요.`, pl: `Proszę zatrzymać się tutaj.`, ipa: `jo-gi-so se-wo dżu-se-jo`},{ko: `얼마나 걸려요?`, pl: `Ile to potrwa?`, ipa: `ol-ma-na kol-lyo-jo`},{ko: `천천히 가 주세요.`, pl: `Proszę jechać powoli.`, ipa: `czon-czo-ni ka dżu-se-jo`},{ko: `카드 돼요?`, pl: `Czy można kartą?`, ipa: `ka-dy twe-jo`}], grammar: `로 / 으로 przy adresie lub miejscu pokazuje kierunek: 공항으로, 이 주소로. 돼요? w praktyce oznacza „czy da się / czy można?”. 카드 돼요? to krótkie i naturalne pytanie, czy można zapłacić kartą.`, practice: [`Poproś kierowcę o przejazd na lotnisko.`,`Zapytaj, ile potrwa trasa.`,`Powiedz „Proszę zatrzymać się tutaj”.`,`Zapytaj, czy można zapłacić kartą.`,`Ułóż zdanie z 이 주소로.`]},{day: 15, title: `Hotel i zameldowanie`, title_native: `호텔과 체크인`, focus: `Nauczysz się słów i zwrotów potrzebnych przy meldowaniu się w hotelu. Przyda się to w hotelu w Myeongdong, pensjonacie na Jeju lub hostelu w Hongdae.`, vocab: [{ko: `체크인`, pl: `zameldowanie`, ipa: `cze-khy-in`},{ko: `체크아웃`, pl: `wymeldowanie`, ipa: `cze-khy-a-ut`},{ko: `예약 번호`, pl: `numer rezerwacji`, ipa: `je-jak pon-ho`},{ko: `여권`, pl: `paszport`, ipa: `jo-kwon`},{ko: `방`, pl: `pokój`, ipa: `pang`},{ko: `키`, pl: `klucz / karta`, ipa: `khi`},{ko: `엘리베이터`, pl: `winda`, ipa: `el-li-be-i-to`},{ko: `조식`, pl: `śniadanie hotelowe`, ipa: `czo-sik`},{ko: `와이파이`, pl: `Wi-Fi`, ipa: `wa-i-pa-i`},{ko: `비밀번호`, pl: `hasło`, ipa: `pi-mil-bon-ho`}], phrases: [{ko: `체크인하고 싶어요.`, pl: `Chcę się zameldować.`, ipa: `cze-khy-in-ha-go si-po-jo`},{ko: `예약했어요.`, pl: `Mam rezerwację.`, ipa: `je-ja-khe-so-jo`},{ko: `여권 여기 있어요.`, pl: `Paszport jest tutaj.`, ipa: `jo-kwon jo-gi i-so-jo`},{ko: `방 키 주세요.`, pl: `Proszę klucz do pokoju.`, ipa: `pang khi dżu-se-jo`},{ko: `와이파이 비밀번호가 뭐예요?`, pl: `Jakie jest hasło do Wi-Fi?`, ipa: `wa-i-pa-i pi-mil-bon-ho-ga mwo-je-jo`},{ko: `조식은 몇 시예요?`, pl: `O której jest śniadanie?`, ipa: `czo-si-gyn mjot si-je-jo`}], grammar: `하고 싶어요 oznacza „chcę zrobić”. Możesz połączyć rzeczownik z 하다, na przykład 체크인하다 — meldować się. Pytanie 뭐예요? jest bardzo praktyczne przy hasłach, numerach i nazwach: 비밀번호가 뭐예요?`, practice: [`Powiedz, że chcesz się zameldować.`,`Powiedz, że masz rezerwację.`,`Zapytaj o hasło do Wi-Fi.`,`Zapytaj, o której jest śniadanie.`,`Odegraj rozmowę w recepcji z trzema zdaniami.`]},{day: 16, title: `Problemy w pokoju`, title_native: `방 문제`, focus: `Nauczysz się zgłaszać proste problemy w hotelu, takie jak brak ciepłej wody, niedziałająca klimatyzacja lub potrzeba dodatkowego ręcznika. To bardzo ważne, jeśli chcesz szybko i spokojnie rozwiązać sytuację.`, vocab: [{ko: `문제`, pl: `problem`, ipa: `mun-dże`},{ko: `수건`, pl: `ręcznik`, ipa: `su-gon`},{ko: `뜨거운 물`, pl: `ciepła woda`, ipa: `tty-go-un mul`},{ko: `에어컨`, pl: `klimatyzacja`, ipa: `e-o-kon`},{ko: `난방`, pl: `ogrzewanie`, ipa: `nan-bang`},{ko: `고장`, pl: `awaria`, ipa: `ko-dżang`},{ko: `소음`, pl: `hałas`, ipa: `so-ym`},{ko: `청소`, pl: `sprzątanie`, ipa: `czong-so`},{ko: `바꿔 주세요`, pl: `proszę wymienić`, ipa: `pa-kkwo dżu-se-jo`},{ko: `필요해요`, pl: `potrzebuję`, ipa: `pi-ryo-he-jo`}], phrases: [{ko: `에어컨이 안 돼요.`, pl: `Klimatyzacja nie działa.`, ipa: `e-o-ko-ni an twe-jo`},{ko: `뜨거운 물이 안 나와요.`, pl: `Nie ma ciepłej wody.`, ipa: `tty-go-un mu-ri an na-wa-jo`},{ko: `수건이 더 필요해요.`, pl: `Potrzebuję więcej ręczników.`, ipa: `su-go-ni do pi-ryo-he-jo`},{ko: `방을 바꿔 주세요.`, pl: `Proszę zmienić pokój.`, ipa: `pang-yl pa-kkwo dżu-se-jo`},{ko: `소음이 있어요.`, pl: `Jest hałas.`, ipa: `so-y-mi i-so-jo`},{ko: `청소해 주세요.`, pl: `Proszę posprzątać.`, ipa: `czong-so-he dżu-se-jo`}], grammar: `안 przed czasownikiem lub wyrażeniem oznacza przeczenie: 안 돼요, 안 나와요. 필요해요 oznacza „potrzebuję” i łączy się z rzeczownikiem: 수건이 필요해요. 더 dodaje znaczenie „więcej” albo „jeszcze”.`, practice: [`Powiedz, że klimatyzacja nie działa.`,`Poproś o więcej ręczników.`,`Powiedz, że nie ma ciepłej wody.`,`Poproś o zmianę pokoju.`,`Ułóż krótką wiadomość do recepcji po koreańsku.`]},{day: 17, title: `Zakupy i ceny`, title_native: `쇼핑과 가격`, focus: `Nauczysz się pytać o ceny, rozmiary i kolory podczas zakupów. Przyda się to w Myeongdong, centrum handlowym COEX albo na targu Namdaemun.`, vocab: [{ko: `쇼핑`, pl: `zakupy`, ipa: `syo-ping`},{ko: `가게`, pl: `sklep`, ipa: `ka-ge`},{ko: `가격`, pl: `cena`, ipa: `ka-gjok`},{ko: `얼마`, pl: `ile`, ipa: `ol-ma`},{ko: `비싸요`, pl: `drogie`, ipa: `pi-ssa-jo`},{ko: `싸요`, pl: `tanie`, ipa: `ssa-jo`},{ko: `색`, pl: `kolor`, ipa: `sek`},{ko: `크기`, pl: `rozmiar / wielkość`, ipa: `khy-gi`},{ko: `작아요`, pl: `małe`, ipa: `cza-ga-jo`},{ko: `커요`, pl: `duże`, ipa: `kho-jo`}], phrases: [{ko: `이거 얼마예요?`, pl: `Ile to kosztuje?`, ipa: `i-go ol-ma-je-jo`},{ko: `너무 비싸요.`, pl: `To za drogie.`, ipa: `no-mu pi-ssa-jo`},{ko: `조금 깎아 주세요.`, pl: `Proszę trochę obniżyć cenę.`, ipa: `czo-gym kka-kka dżu-se-jo`},{ko: `다른 색 있어요?`, pl: `Czy jest inny kolor?`, ipa: `ta-ryn sek i-so-jo`},{ko: `더 큰 사이즈 있어요?`, pl: `Czy jest większy rozmiar?`, ipa: `to khyn sa-i-dzy i-so-jo`},{ko: `이걸로 할게요.`, pl: `Wezmę to.`, ipa: `i-gol-lo hal-ge-jo`}], grammar: `이거 oznacza „to”, a 이걸로 할게요 znaczy „wezmę to / wybiorę to”. 다른 oznacza „inny”, więc 다른 색 to „inny kolor”. W Korei targowanie jest możliwe na niektórych targach, ale nie w typowych sklepach sieciowych.`, practice: [`Zapytaj o cenę pamiątki.`,`Powiedz, że coś jest za drogie.`,`Zapytaj o inny kolor.`,`Powiedz „Wezmę to”.`,`Zapytaj o większy rozmiar.`]},{day: 18, title: `Ubrania i rozmiary`, title_native: `옷과 사이즈`, focus: `Dziś skupisz się na kupowaniu ubrań i przymierzaniu. Nauczysz się pytać o rozmiar, przymierzalnię i możliwość zwrotu.`, vocab: [{ko: `옷`, pl: `ubranie`, ipa: `ot`},{ko: `셔츠`, pl: `koszula`, ipa: `syo-czy`},{ko: `바지`, pl: `spodnie`, ipa: `pa-dżi`},{ko: `신발`, pl: `buty`, ipa: `sin-bal`},{ko: `사이즈`, pl: `rozmiar`, ipa: `sa-i-dzy`},{ko: `작은`, pl: `mały`, ipa: `cza-gyn`},{ko: `큰`, pl: `duży`, ipa: `khyn`},{ko: `탈의실`, pl: `przymierzalnia`, ipa: `ta-ri-sil`},{ko: `교환`, pl: `wymiana`, ipa: `kyo-hwan`},{ko: `환불`, pl: `zwrot pieniędzy`, ipa: `hwan-bul`}], phrases: [{ko: `입어 봐도 돼요?`, pl: `Czy mogę przymierzyć?`, ipa: `i-bo bwa-do twe-jo`},{ko: `탈의실은 어디예요?`, pl: `Gdzie jest przymierzalnia?`, ipa: `ta-ri-si-lyn o-di-je-jo`},{ko: `작은 사이즈 있어요?`, pl: `Czy jest mniejszy rozmiar?`, ipa: `cza-gyn sa-i-dzy i-so-jo`},{ko: `큰 사이즈 주세요.`, pl: `Proszę większy rozmiar.`, ipa: `khyn sa-i-dzy dżu-se-jo`},{ko: `교환 돼요?`, pl: `Czy można wymienić?`, ipa: `kyo-hwan twe-jo`},{ko: `환불 돼요?`, pl: `Czy można zwrócić?`, ipa: `hwan-bul twe-jo`}], grammar: `-아/어 봐도 돼요? oznacza „czy mogę spróbować?”. 입어 봐도 돼요? dosłownie znaczy „czy mogę spróbować założyć?”. 돼요 jest bardzo użyteczne przy pytaniu o możliwość: 교환 돼요?, 환불 돼요?`, practice: [`Zapytaj, czy możesz przymierzyć koszulę.`,`Zapytaj, gdzie jest przymierzalnia.`,`Poproś o większy rozmiar.`,`Zapytaj, czy można wymienić produkt.`,`Ułóż dialog w sklepie odzieżowym.`]},{day: 19, title: `Pogoda i plan dnia`, title_native: `날씨와 하루 계획`, focus: `Nauczysz się mówić o pogodzie i prostych planach. Przyda się to przy planowaniu spaceru po pałacu Gyeongbokgung, wycieczki na Namsan lub plaży w Busanie.`, vocab: [{ko: `날씨`, pl: `pogoda`, ipa: `nal-ssi`},{ko: `비`, pl: `deszcz`, ipa: `pi`},{ko: `눈`, pl: `śnieg`, ipa: `nun`},{ko: `바람`, pl: `wiatr`, ipa: `pa-ram`},{ko: `더워요`, pl: `jest gorąco`, ipa: `to-wo-jo`},{ko: `추워요`, pl: `jest zimno`, ipa: `czu-wo-jo`},{ko: `맑아요`, pl: `jest pogodnie`, ipa: `mal-ga-jo`},{ko: `흐려요`, pl: `jest pochmurno`, ipa: `hy-ryo-jo`},{ko: `우산`, pl: `parasol`, ipa: `u-san`},{ko: `계획`, pl: `plan`, ipa: `kye-hwek`}], phrases: [{ko: `오늘 날씨가 좋아요.`, pl: `Dzisiaj pogoda jest dobra.`, ipa: `o-nyl nal-ssi-ga czo-a-jo`},{ko: `비가 와요.`, pl: `Pada deszcz.`, ipa: `pi-ga wa-jo`},{ko: `우산이 필요해요.`, pl: `Potrzebuję parasola.`, ipa: `u-sa-ni pi-ryo-he-jo`},{ko: `너무 더워요.`, pl: `Jest za gorąco.`, ipa: `no-mu to-wo-jo`},{ko: `내일 뭐 해요?`, pl: `Co robisz jutro?`, ipa: `ne-il mwo he-jo`},{ko: `오늘은 쉬고 싶어요.`, pl: `Dzisiaj chcę odpocząć.`, ipa: `o-ny-ryn swi-go si-po-jo`}], grammar: `날씨가 좋아요 znaczy „pogoda jest dobra”, a 비가 와요 dosłownie „deszcz przychodzi”, czyli „pada”. 하고 싶어요 po rdzeniu czasownika oznacza „chcę robić”, na przykład 쉬고 싶어요 — „chcę odpocząć”.`, practice: [`Powiedz, że pada deszcz.`,`Powiedz, że potrzebujesz parasola.`,`Opisz pogodę jako dobrą.`,`Zapytaj drugą osobę, co robi jutro.`,`Powiedz, że dzisiaj chcesz odpocząć.`]},{day: 20, title: `Zdrowie i apteka`, title_native: `건강과 약국`, focus: `Nauczysz się podstawowych zwrotów do użycia w aptece lub przy złym samopoczuciu. To ważne podczas podróży, zwłaszcza jeśli boli cię głowa, żołądek albo masz przeziębienie.`, vocab: [{ko: `약국`, pl: `apteka`, ipa: `jak-guk`},{ko: `약`, pl: `lekarstwo`, ipa: `jak`},{ko: `두통`, pl: `ból głowy`, ipa: `du-tong`},{ko: `감기`, pl: `przeziębienie`, ipa: `kam-gi`},{ko: `열`, pl: `gorączka`, ipa: `jol`},{ko: `기침`, pl: `kaszel`, ipa: `ki-czim`},{ko: `배`, pl: `brzuch`, ipa: `pe`},{ko: `아파요`, pl: `boli`, ipa: `a-pa-jo`},{ko: `알레르기`, pl: `alergia`, ipa: `al-le-ry-gi`},{ko: `처방전`, pl: `recepta`, ipa: `czo-bang-dżon`}], phrases: [{ko: `머리가 아파요.`, pl: `Boli mnie głowa.`, ipa: `mo-ri-ga a-pa-jo`},{ko: `배가 아파요.`, pl: `Boli mnie brzuch.`, ipa: `pe-ga a-pa-jo`},{ko: `감기약 주세요.`, pl: `Proszę lek na przeziębienie.`, ipa: `kam-gi-yak dżu-se-jo`},{ko: `알레르기가 있어요.`, pl: `Mam alergię.`, ipa: `al-le-ry-gi-ga i-so-jo`},{ko: `처방전이 필요해요?`, pl: `Czy potrzebna jest recepta?`, ipa: `czo-bang-dżo-ni pi-ryo-he-jo`},{ko: `하루에 몇 번 먹어요?`, pl: `Ile razy dziennie brać?`, ipa: `ha-ru-e mjot pon mo-go-jo`}], grammar: `Część ciała + 이/가 아파요 oznacza „boli mnie...”: 머리가 아파요, 배가 아파요. 약 to lek, a połączenia typu 감기약 są bardzo częste. 먹어요 dosłownie znaczy „jeść”, ale przy lekach oznacza „brać”.`, practice: [`Powiedz, że boli cię głowa.`,`Poproś o lek na przeziębienie.`,`Powiedz, że masz alergię.`,`Zapytaj, czy potrzebna jest recepta.`,`Zapytaj, ile razy dziennie brać lek.`]},{day: 21, title: `Nagłe sytuacje i bezpieczeństwo`, title_native: `긴급 상황과 안전`, focus: `Nauczysz się prostych zwrotów na wypadek sytuacji awaryjnej. To dzień praktyczny, ale ważny: zgubiony paszport, potrzeba pomocy, policja lub szpital.`, vocab: [{ko: `도와주세요`, pl: `pomocy / proszę pomóc`, ipa: `to-wa-dżu-se-jo`},{ko: `긴급`, pl: `pilne / nagłe`, ipa: `kin-gyp`},{ko: `경찰`, pl: `policja`, ipa: `kyong-czal`},{ko: `병원`, pl: `szpital`, ipa: `pjong-won`},{ko: `대사관`, pl: `ambasada`, ipa: `te-sa-gwan`},{ko: `여권`, pl: `paszport`, ipa: `jo-kwon`},{ko: `잃어버렸어요`, pl: `zgubiłem / zgubiłam`, ipa: `i-ro-bo-ryo-so-jo`},{ko: `위험해요`, pl: `to niebezpieczne`, ipa: `wi-hom-he-jo`},{ko: `전화`, pl: `telefon`, ipa: `czo-nhwa`},{ko: `신고`, pl: `zgłoszenie`, ipa: `sin-go`}], phrases: [{ko: `도와주세요!`, pl: `Pomocy!`, ipa: `to-wa-dżu-se-jo`},{ko: `여권을 잃어버렸어요.`, pl: `Zgubiłem paszport.`, ipa: `jo-kwo-nyl i-ro-bo-ryo-so-jo`},{ko: `경찰을 불러 주세요.`, pl: `Proszę wezwać policję.`, ipa: `kyong-cza-ryl pul-lo dżu-se-jo`},{ko: `병원에 가야 해요.`, pl: `Muszę iść do szpitala.`, ipa: `pjong-wo-ne ka-ja he-jo`},{ko: `대사관은 어디예요?`, pl: `Gdzie jest ambasada?`, ipa: `te-sa-gwa-nyn o-di-je-jo`},{ko: `전화해 주세요.`, pl: `Proszę zadzwonić.`, ipa: `czo-nhwa-he dżu-se-jo`}], grammar: `-아/어야 해요 oznacza „muszę”. 가야 해요 to „muszę iść”, 전화해야 해요 to „muszę zadzwonić”. 잃어버렸어요 jest gotową formą „zgubiłem/zgubiłam”, bardzo przydatną przy paszporcie, telefonie lub portfelu.`, practice: [`Powiedz „Pomocy!”.`,`Powiedz, że zgubiłeś paszport.`,`Poproś o wezwanie policji.`,`Powiedz, że musisz iść do szpitala.`,`Zapytaj, gdzie jest ambasada.`]},{day: 22, title: `Telefon, internet i komunikacja`, title_native: `전화, 인터넷, 소통`, focus: `Nauczysz się pytać o Wi-Fi, kartę SIM i podstawowe problemy z telefonem. To przyda się na lotnisku Incheon, w hotelu, kawiarni i sklepie z elektroniką.`, vocab: [{ko: `전화기`, pl: `telefon`, ipa: `czo-nhwa-gi`},{ko: `휴대폰`, pl: `telefon komórkowy`, ipa: `hyu-de-pon`},{ko: `인터넷`, pl: `internet`, ipa: `in-to-net`},{ko: `와이파이`, pl: `Wi-Fi`, ipa: `wa-i-pa-i`},{ko: `비밀번호`, pl: `hasło`, ipa: `pi-mil-bon-ho`},{ko: `심카드`, pl: `karta SIM`, ipa: `sim-ka-dy`},{ko: `충전기`, pl: `ładowarka`, ipa: `czung-dżon-gi`},{ko: `배터리`, pl: `bateria`, ipa: `pe-to-ri`},{ko: `고장났어요`, pl: `zepsuło się`, ipa: `ko-dżang-na-so-jo`},{ko: `연결`, pl: `połączenie`, ipa: `jon-gjol`}], phrases: [{ko: `와이파이 있어요?`, pl: `Czy jest Wi-Fi?`, ipa: `wa-i-pa-i i-so-jo`},{ko: `비밀번호가 뭐예요?`, pl: `Jakie jest hasło?`, ipa: `pi-mil-bon-ho-ga mwo-je-jo`},{ko: `심카드 사고 싶어요.`, pl: `Chcę kupić kartę SIM.`, ipa: `sim-ka-dy sa-go si-po-jo`},{ko: `충전기 있어요?`, pl: `Czy jest ładowarka?`, ipa: `czung-dżon-gi i-so-jo`},{ko: `인터넷이 안 돼요.`, pl: `Internet nie działa.`, ipa: `in-to-ne-si an twe-jo`},{ko: `휴대폰 배터리가 없어요.`, pl: `Telefon nie ma baterii.`, ipa: `hyu-de-pon pe-to-ri-ga op-so-jo`}], grammar: `사고 싶어요 oznacza „chcę kupić”. Możesz użyć tego z rzeczami w sklepie: 심카드 사고 싶어요, 충전기 사고 싶어요. 없어요 oznacza „nie ma”, ale też „nie mam”, więc 배터리가 없어요 może znaczyć „nie mam baterii”.`, practice: [`Zapytaj o Wi-Fi.`,`Zapytaj o hasło.`,`Powiedz, że chcesz kupić kartę SIM.`,`Powiedz, że internet nie działa.`,`Zapytaj, czy jest ładowarka.`]},{day: 23, title: `Umawianie się i spotkania`, title_native: `약속과 만남`, focus: `Nauczysz się umawiać godzinę i miejsce spotkania. Przyda się to przy spotkaniu z lokalnym znajomym, przewodnikiem albo innymi podróżnikami.`, vocab: [{ko: `약속`, pl: `spotkanie / umówienie`, ipa: `jak-sok`},{ko: `만나다`, pl: `spotykać`, ipa: `man-na-da`},{ko: `시간`, pl: `czas`, ipa: `si-gan`},{ko: `장소`, pl: `miejsce`, ipa: `czang-so`},{ko: `앞`, pl: `przed`, ipa: `ap`},{ko: `뒤`, pl: `za`, ipa: `twi`},{ko: `근처`, pl: `okolica / blisko`, ipa: `kyn-czo`},{ko: `카카오톡`, pl: `KakaoTalk`, ipa: `ka-ka-o-tok`},{ko: `보내다`, pl: `wysyłać`, ipa: `po-ne-da`},{ko: `늦어요`, pl: `spóźniam się / jest późno`, ipa: `ny-dzo-jo`}], phrases: [{ko: `몇 시에 만나요?`, pl: `O której się spotykamy?`, ipa: `mjot si-e man-na-jo`},{ko: `어디에서 만나요?`, pl: `Gdzie się spotykamy?`, ipa: `o-di-e-so man-na-jo`},{ko: `역 앞에서 만나요.`, pl: `Spotkajmy się przed stacją.`, ipa: `jog a-pe-so man-na-jo`},{ko: `조금 늦어요.`, pl: `Trochę się spóźnię.`, ipa: `czo-gym ny-dzo-jo`},{ko: `카카오톡으로 보내 주세요.`, pl: `Proszę wysłać przez KakaoTalk.`, ipa: `ka-ka-o-to-gy-ro po-ne dżu-se-jo`},{ko: `근처에 있어요.`, pl: `Jestem w pobliżu.`, ipa: `kyn-czo-e i-so-jo`}], grammar: `에서 może oznaczać miejsce akcji: 역 앞에서 만나요 — spotkajmy się przed stacją. 몇 시에 pyta „o której godzinie”. 늦어요 znaczy „jest późno” albo „spóźniam się”, zależnie od kontekstu.`, practice: [`Zapytaj, o której się spotykacie.`,`Zaproponuj spotkanie przed stacją.`,`Powiedz, że trochę się spóźnisz.`,`Poproś o wysłanie informacji przez KakaoTalk.`,`Powiedz, że jesteś w pobliżu.`]},{day: 24, title: `Zwiedzanie i atrakcje`, title_native: `관광과 명소`, focus: `Nauczysz się rozmawiać o zwiedzaniu, biletach i godzinach otwarcia. Sceny pasują do pałacu Gyeongbokgung, wieży N Seoul Tower, muzeów i wycieczki na Jeju.`, vocab: [{ko: `관광`, pl: `zwiedzanie / turystyka`, ipa: `kwan-gwang`},{ko: `명소`, pl: `atrakcja / znane miejsce`, ipa: `mjong-so`},{ko: `궁`, pl: `pałac`, ipa: `kung`},{ko: `박물관`, pl: `muzeum`, ipa: `pang-mul-gwan`},{ko: `입장권`, pl: `bilet wstępu`, ipa: `ip-czang-kwon`},{ko: `사진`, pl: `zdjęcie`, ipa: `sa-dżin`},{ko: `지도`, pl: `mapa`, ipa: `czi-do`},{ko: `가이드`, pl: `przewodnik`, ipa: `ka-i-dy`},{ko: `열다`, pl: `otwierać`, ipa: `jol-da`},{ko: `닫다`, pl: `zamykać`, ipa: `tat-da`}], phrases: [{ko: `입장권 하나 주세요.`, pl: `Proszę jeden bilet wstępu.`, ipa: `ip-czang-kwon ha-na dżu-se-jo`},{ko: `사진 찍어도 돼요?`, pl: `Czy można robić zdjęcia?`, ipa: `sa-dżin cci-go-do twe-jo`},{ko: `몇 시에 닫아요?`, pl: `O której zamykacie?`, ipa: `mjot si-e ta-da-jo`},{ko: `지도 주세요.`, pl: `Proszę mapę.`, ipa: `czi-do dżu-se-jo`},{ko: `가이드 투어 있어요?`, pl: `Czy jest wycieczka z przewodnikiem?`, ipa: `ka-i-dy tu-o i-so-jo`},{ko: `여기 유명해요?`, pl: `Czy to miejsce jest znane?`, ipa: `jo-gi ju-mjong-he-jo`}], grammar: `-아/어도 돼요? oznacza „czy można?”. 사진 찍어도 돼요? jest bardzo przydatne w muzeach, świątyniach i pałacach. 유명해요 oznacza „jest znane / słynne”, więc możesz zapytać lokalną osobę o polecenia.`, practice: [`Kup jeden bilet wstępu.`,`Zapytaj, czy można robić zdjęcia.`,`Zapytaj, o której muzeum się zamyka.`,`Poproś o mapę.`,`Zapytaj, czy jest wycieczka z przewodnikiem.`]},{day: 25, title: `Małe rozmowy z lokalnymi`, title_native: `현지인과 짧은 대화`, focus: `Nauczysz się prowadzić prostą, miłą rozmowę z lokalną osobą. To przyda się w hostelu, kawiarni, na wycieczce lub podczas czekania w kolejce.`, vocab: [{ko: `한국어`, pl: `język koreański`, ipa: `han-gu-go`},{ko: `조금`, pl: `trochę`, ipa: `czo-gym`},{ko: `잘`, pl: `dobrze`, ipa: `czal`},{ko: `못`, pl: `nie umieć / słabo`, ipa: `mot`},{ko: `좋아해요`, pl: `lubię`, ipa: `czo-a-he-jo`},{ko: `여행`, pl: `podróż`, ipa: `jo-heng`},{ko: `음악`, pl: `muzyka`, ipa: `y-mak`},{ko: `영화`, pl: `film`, ipa: `jong-hwa`},{ko: `취미`, pl: `hobby`, ipa: `czwi-mi`},{ko: `친절해요`, pl: `miły / uprzejmy`, ipa: `czin-dżol-he-jo`}], phrases: [{ko: `한국어를 조금 해요.`, pl: `Mówię trochę po koreańsku.`, ipa: `han-gu-go-ryl czo-gym he-jo`},{ko: `한국어를 잘 못해요.`, pl: `Nie mówię dobrze po koreańsku.`, ipa: `han-gu-go-ryl czal mo-te-jo`},{ko: `한국 음식을 좋아해요.`, pl: `Lubię koreańskie jedzenie.`, ipa: `han-guk ym-si-gyl czo-a-he-jo`},{ko: `여행 중이에요.`, pl: `Jestem w podróży.`, ipa: `jo-heng dżung-i-e-jo`},{ko: `서울이 정말 좋아요.`, pl: `Seul bardzo mi się podoba.`, ipa: `so-u-ri czong-mal czo-a-jo`},{ko: `친절해서 감사합니다.`, pl: `Dziękuję za uprzejmość.`, ipa: `czin-dżol-he-so kam-sa-ham-ni-da`}], grammar: `좋아해요 oznacza „lubię”, a 좋아요 oznacza „jest dobre / podoba mi się”. 한국 음식을 좋아해요 mówi o twojej preferencji, a 서울이 좋아요 mówi, że Seul ci się podoba. 잘 못해요 to uprzejmy sposób powiedzenia, że nie robisz czegoś dobrze.`, practice: [`Powiedz, że mówisz trochę po koreańsku.`,`Powiedz, że lubisz koreańskie jedzenie.`,`Powiedz, że jesteś w podróży.`,`Powiedz, że Seul ci się podoba.`,`Podziękuj komuś za uprzejmość.`]},{day: 26, title: `Zgadzanie się, odmawianie i opinie`, title_native: `동의, 거절, 의견`, focus: `Nauczysz się naturalnie mówić „tak”, „nie”, „może”, „dobrze” i wyrażać proste opinie. To pomaga w rozmowie, zakupach i planowaniu dnia.`, vocab: [{ko: `좋아요`, pl: `dobrze / podoba mi się`, ipa: `czo-a-jo`},{ko: `싫어요`, pl: `nie lubię / nie chcę`, ipa: `si-ro-jo`},{ko: `맞아요`, pl: `zgadza się`, ipa: `ma-dża-jo`},{ko: `아니에요`, pl: `nie jest / nie`, ipa: `a-ni-e-jo`},{ko: `maybe`, pl: `może`, ipa: `me-i-bi`},{ko: `아마`, pl: `prawdopodobnie / może`, ipa: `a-ma`},{ko: `괜찮아요`, pl: `w porządku`, ipa: `kwan-czan-a-jo`},{ko: `별로`, pl: `niezbyt`, ipa: `pjol-lo`},{ko: `정말`, pl: `naprawdę`, ipa: `czong-mal`},{ko: `재미있어요`, pl: `ciekawe / zabawne`, ipa: `cze-mi-i-so-jo`}], phrases: [{ko: `네, 좋아요.`, pl: `Tak, dobrze.`, ipa: `ne czo-a-jo`},{ko: `아니요, 괜찮아요.`, pl: `Nie, dziękuję / w porządku.`, ipa: `a-ni-jo kwan-czan-a-jo`},{ko: `정말 좋아요.`, pl: `Naprawdę mi się podoba.`, ipa: `czong-mal czo-a-jo`},{ko: `별로예요.`, pl: `Niezbyt.`, ipa: `pjol-lo-je-jo`},{ko: `맞아요.`, pl: `Zgadza się.`, ipa: `ma-dża-jo`},{ko: `아마 내일 갈게요.`, pl: `Może pójdę jutro.`, ipa: `a-ma ne-il kal-ge-jo`}], grammar: `괜찮아요 może znaczyć „wszystko w porządku”, ale też uprzejme „nie, dziękuję”. 별로예요 oznacza „niezbyt”, ale brzmi łagodniej niż mocne 싫어요. Koreańskie odmowy bywają pośrednie, więc ton i kontekst są ważne.`, practice: [`Zgódź się na propozycję: „Tak, dobrze”.`,`Uprzejmie odmów dodatkowej torby w sklepie.`,`Powiedz, że coś naprawdę ci się podoba.`,`Powiedz „niezbyt” o miejscu, które cię nie zachwyciło.`,`Ułóż zdanie z 아마.`]},{day: 27, title: `Pieniądze, płatności i bankomat`, title_native: `돈, 결제, ATM`, focus: `Nauczysz się mówić o płatności kartą, gotówką, bankomacie i paragonie. To praktyczne w restauracjach, sklepach i przy transporcie.`, vocab: [{ko: `돈`, pl: `pieniądze`, ipa: `ton`},{ko: `원`, pl: `won, waluta Korei`, ipa: `won`},{ko: `카드`, pl: `karta`, ipa: `ka-dy`},{ko: `현금`, pl: `gotówka`, ipa: `hjon-gym`},{ko: `결제`, pl: `płatność`, ipa: `kjol-dże`},{ko: `영수증`, pl: `paragon`, ipa: `jong-su-dżyng`},{ko: `ATM`, pl: `bankomat`, ipa: `e-i-ti-em`},{ko: `수수료`, pl: `opłata / prowizja`, ipa: `su-su-ryo`},{ko: `잔돈`, pl: `reszta`, ipa: `czan-don`},{ko: `계산대`, pl: `kasa`, ipa: `kye-san-de`}], phrases: [{ko: `카드로 결제할게요.`, pl: `Zapłacę kartą.`, ipa: `ka-dy-ro kjol-dże-hal-ge-jo`},{ko: `현금으로 할게요.`, pl: `Zapłacę gotówką.`, ipa: `hjon-gy-my-ro hal-ge-jo`},{ko: `영수증 주세요.`, pl: `Proszę paragon.`, ipa: `jong-su-dżyng dżu-se-jo`},{ko: `ATM은 어디예요?`, pl: `Gdzie jest bankomat?`, ipa: `e-i-ti-e-myn o-di-je-jo`},{ko: `수수료 있어요?`, pl: `Czy jest prowizja?`, ipa: `su-su-ryo i-so-jo`},{ko: `잔돈 괜찮아요.`, pl: `Reszta nie trzeba / w porządku.`, ipa: `czan-don kwan-czan-a-jo`}], grammar: `결제할게요 oznacza „zapłacę” w kontekście płatności. -으로 / -로 wskazuje metodę: 카드로, 현금으로. 있어요? pyta, czy coś istnieje, więc 수수료 있어요? znaczy „czy jest prowizja?”.`, practice: [`Powiedz, że zapłacisz kartą.`,`Zapytaj, gdzie jest bankomat.`,`Poproś o paragon.`,`Zapytaj, czy jest prowizja.`,`Powiedz, że zapłacisz gotówką.`]},{day: 28, title: `Transport między miastami`, title_native: `도시 간 이동`, focus: `Nauczysz się słownictwa do podróży pociągiem, autobusem i samolotem. Przyda się przy wyjeździe z Seulu do Busanu, Jeonju, Gyeongju lub na Jeju.`, vocab: [{ko: `기차`, pl: `pociąg`, ipa: `ki-cza`},{ko: `고속버스`, pl: `autobus dalekobieżny`, ipa: `ko-sok-po-sy`},{ko: `공항버스`, pl: `autobus lotniskowy`, ipa: `kong-hang-po-sy`},{ko: `KTX`, pl: `szybki pociąg KTX`, ipa: `khe-i-thi-ek-sy`},{ko: `표`, pl: `bilet`, ipa: `pjo`},{ko: `좌석`, pl: `miejsce siedzące`, ipa: `cwa-sok`},{ko: `출발 시간`, pl: `godzina odjazdu`, ipa: `czul-bal si-gan`},{ko: `도착 시간`, pl: `godzina przyjazdu`, ipa: `to-czak si-gan`},{ko: `매진`, pl: `wyprzedane`, ipa: `me-dżin`},{ko: `왕복`, pl: `w obie strony`, ipa: `wang-bok`}], phrases: [{ko: `부산 가는 표 주세요.`, pl: `Proszę bilet do Busanu.`, ipa: `pu-san ka-nyn pjo dżu-se-jo`},{ko: `왕복이에요.`, pl: `W obie strony.`, ipa: `wang-bo-gi-e-jo`},{ko: `편도예요.`, pl: `W jedną stronę.`, ipa: `pjon-do-je-jo`},{ko: `좌석 있어요?`, pl: `Czy są miejsca?`, ipa: `cwa-sok i-so-jo`},{ko: `몇 시에 출발해요?`, pl: `O której odjeżdża?`, ipa: `mjot si-e czul-bal-he-jo`},{ko: `매진이에요?`, pl: `Czy wyprzedane?`, ipa: `me-dżi-ni-e-jo`}], grammar: `가는 przed rzeczownikiem oznacza „jadący do” lub „idący do”, na przykład 부산 가는 표 — bilet do Busanu. 편도 to bilet w jedną stronę, a 왕복 w obie strony. Przy pytaniu o rozkład bardzo przydatne jest 몇 시에 출발해요?`, practice: [`Kup bilet do Busanu.`,`Powiedz, że chcesz bilet w jedną stronę.`,`Zapytaj, czy są miejsca.`,`Zapytaj, o której odjeżdża pociąg.`,`Zapytaj, czy bilety są wyprzedane.`]},{day: 29, title: `Pamiątki i wysyłka`, title_native: `기념품과 배송`, focus: `Nauczysz się kupować pamiątki i pytać o pakowanie oraz wysyłkę. To przyda się w sklepach z kosmetykami, herbatą, ceramiką i drobnymi prezentami.`, vocab: [{ko: `기념품`, pl: `pamiątka`, ipa: `ki-njom-pum`},{ko: `선물`, pl: `prezent`, ipa: `son-mul`},{ko: `포장`, pl: `pakowanie`, ipa: `po-dżang`},{ko: `배송`, pl: `wysyłka / dostawa`, ipa: `pe-song`},{ko: `주소`, pl: `adres`, ipa: `czu-so`},{ko: `무게`, pl: `waga`, ipa: `mu-ge`},{ko: `깨지기 쉬워요`, pl: `łatwo się tłucze`, ipa: `kke-dżi-gi swi-wo-jo`},{ko: `화장품`, pl: `kosmetyki`, ipa: `hwa-dżang-pum`},{ko: `차`, pl: `herbata`, ipa: `cza`},{ko: `도자기`, pl: `ceramika`, ipa: `to-dża-gi`}], phrases: [{ko: `선물 포장해 주세요.`, pl: `Proszę zapakować na prezent.`, ipa: `son-mul po-dżang-he dżu-se-jo`},{ko: `배송 가능해요?`, pl: `Czy wysyłka jest możliwa?`, ipa: `pe-song ka-nyng-he-jo`},{ko: `폴란드로 보낼 수 있어요?`, pl: `Czy można wysłać do Polski?`, ipa: `pol-lan-dy-ro po-nel su i-so-jo`},{ko: `깨지기 쉬워요.`, pl: `To łatwo się tłucze.`, ipa: `kke-dżi-gi swi-wo-jo`},{ko: `주소를 써 주세요.`, pl: `Proszę napisać adres.`, ipa: `czu-so-ryl sso dżu-se-jo`},{ko: `기념품을 사고 싶어요.`, pl: `Chcę kupić pamiątki.`, ipa: `ki-njom-pu-myl sa-go si-po-jo`}], grammar: `-ㄹ/을 수 있어요 oznacza „można / potrafię”. 보낼 수 있어요? znaczy „czy można wysłać?”. 가능해요? oznacza „czy jest możliwe?” i działa świetnie w pytaniach podróżnych: 배송 가능해요?`, practice: [`Poproś o zapakowanie prezentu.`,`Zapytaj, czy możliwa jest wysyłka.`,`Zapytaj, czy można wysłać paczkę do Polski.`,`Powiedz, że coś łatwo się tłucze.`,`Powiedz, że chcesz kupić pamiątki.`]},{day: 30, title: `Ostatni dzień i pożegnania`, title_native: `마지막 날과 작별 인사`, focus: `Nauczysz się pożegnań, podziękowań i zwrotów na koniec podróży. To dobry dzień na rozmowę z gospodarzem, personelem hotelu albo nowo poznaną osobą przed wyjazdem.`, vocab: [{ko: `마지막`, pl: `ostatni`, ipa: `ma-dżi-mak`},{ko: `날`, pl: `dzień`, ipa: `nal`},{ko: `출국`, pl: `wyjazd z kraju`, ipa: `czul-guk`},{ko: `공항`, pl: `lotnisko`, ipa: `kong-hang`},{ko: `다음`, pl: `następny`, ipa: `ta-ym`},{ko: `다시`, pl: `znowu`, ipa: `ta-si`},{ko: `기억`, pl: `pamięć / wspomnienie`, ipa: `ki-ok`},{ko: `즐거웠어요`, pl: `było przyjemnie`, ipa: `czyl-go-wo-so-jo`},{ko: `고마웠어요`, pl: `byłem wdzięczny`, ipa: `ko-ma-wo-so-jo`},{ko: `안녕히 계세요`, pl: `do widzenia, gdy ty odchodzisz`, ipa: `an-njong-hi kye-se-jo`}], phrases: [{ko: `오늘이 마지막 날이에요.`, pl: `Dzisiaj jest ostatni dzień.`, ipa: `o-ny-ri ma-dżi-mak na-ri-e-jo`},{ko: `내일 출국해요.`, pl: `Jutro wyjeżdżam z kraju.`, ipa: `ne-il czul-gu-khe-jo`},{ko: `정말 즐거웠어요.`, pl: `Było naprawdę przyjemnie.`, ipa: `czong-mal czyl-go-wo-so-jo`},{ko: `도와줘서 감사합니다.`, pl: `Dziękuję za pomoc.`, ipa: `to-wa-dżwo-so kam-sa-ham-ni-da`},{ko: `다시 오고 싶어요.`, pl: `Chcę przyjechać znowu.`, ipa: `ta-si o-go si-po-jo`},{ko: `안녕히 계세요.`, pl: `Do widzenia.`, ipa: `an-njong-hi kye-se-jo`}], grammar: `-아/어 줘서 감사합니다 oznacza „dziękuję za zrobienie czegoś dla mnie”. 도와줘서 감사합니다 to „dziękuję za pomoc”. 안녕히 계세요 mówi osoba, która odchodzi; jeśli ktoś inny odchodzi, możesz usłyszeć 안녕히 가세요.`, practice: [`Powiedz, że dzisiaj jest ostatni dzień podróży.`,`Powiedz, że jutro wyjeżdżasz z Korei.`,`Podziękuj komuś za pomoc.`,`Powiedz, że chcesz przyjechać znowu.`,`Pożegnaj się uprzejmie z gospodarzem hotelu.`]}];

var CONVERSATIONS_PL_KO = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w kawiarni w dzielnicy Seongsu w Seulu. Barista pyta, czy chcesz napój na miejscu czy na wynos, a ty zamawiasz kawę bez cukru.`, lines: [{who: `them`, ko: `안녕하세요, 주문하시겠어요?`, pl: `Dzień dobry, czy chce pan/pani złożyć zamówienie?`},{who: `you`, ko: `네, 아이스 아메리카노 하나 주세요.`, pl: `Tak, poproszę jedno mrożone americano.`},{who: `them`, ko: `포장이세요, 매장에서 드세요?`, pl: `Na wynos czy na miejscu?`},{who: `you`, ko: `매장에서 마실게요.`, pl: `Wypiję na miejscu.`},{who: `them`, ko: `설탕 넣어 드릴까요?`, pl: `Czy dodać cukier?`},{who: `you`, ko: `아니요, 설탕 빼 주세요.`, pl: `Nie, proszę bez cukru.`},{who: `them`, ko: `다른 것도 필요하세요?`, pl: `Czy potrzeba czegoś jeszcze?`},{who: `you`, ko: `물 조금 주세요.`, pl: `Proszę trochę wody.`},{who: `them`, ko: `네, 총 오천 원입니다.`, pl: `Dobrze, razem pięć tysięcy wonów.`},{who: `you`, ko: `카드로 결제할게요.`, pl: `Zapłacę kartą.`},{who: `them`, ko: `감사합니다. 여기 진동벨입니다.`, pl: `Dziękuję. Oto pager.`},{who: `you`, ko: `감사합니다.`, pl: `Dziękuję.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Myeongdong. Masz rezerwację i pytasz o Wi-Fi oraz śniadanie.`, lines: [{who: `them`, ko: `안녕하세요, 체크인 도와드릴까요?`, pl: `Dzień dobry, czy pomóc przy zameldowaniu?`},{who: `you`, ko: `네, 체크인하고 싶어요.`, pl: `Tak, chcę się zameldować.`},{who: `them`, ko: `예약하셨나요?`, pl: `Czy ma pan/pani rezerwację?`},{who: `you`, ko: `네, 예약했어요.`, pl: `Tak, mam rezerwację.`},{who: `them`, ko: `여권 보여 주세요.`, pl: `Proszę pokazać paszport.`},{who: `you`, ko: `여권 여기 있어요.`, pl: `Paszport jest tutaj.`},{who: `them`, ko: `방은 1205호입니다.`, pl: `Pokój to numer 1205.`},{who: `you`, ko: `와이파이 비밀번호가 뭐예요?`, pl: `Jakie jest hasło do Wi-Fi?`},{who: `them`, ko: `비밀번호는 room1205입니다.`, pl: `Hasło to room1205.`},{who: `you`, ko: `조식은 몇 시예요?`, pl: `O której jest śniadanie?`},{who: `them`, ko: `아침 일곱 시부터 열 시까지입니다.`, pl: `Od siódmej do dziesiątej rano.`},{who: `you`, ko: `감사합니다.`, pl: `Dziękuję.`}]},{id: 3, title: `Pytanie o drogę do stacji metra`, scene: `Spacerujesz po Insadong i chcesz znaleźć najbliższą stację metra. Zatrzymujesz lokalną osobę i prosisz o prostą wskazówkę.`, lines: [{who: `you`, ko: `죄송합니다, 지하철역은 어디예요?`, pl: `Przepraszam, gdzie jest stacja metra?`},{who: `them`, ko: `여기에서 가까워요.`, pl: `Jest blisko stąd.`},{who: `you`, ko: `걸어서 갈 수 있어요?`, pl: `Czy można dojść pieszo?`},{who: `them`, ko: `네, 걸어서 오 분이에요.`, pl: `Tak, pieszo pięć minut.`},{who: `you`, ko: `어떻게 가요?`, pl: `Jak tam dojść?`},{who: `them`, ko: `곧장 가세요.`, pl: `Proszę iść prosto.`},{who: `you`, ko: `그다음에는요?`, pl: `A potem?`},{who: `them`, ko: `오른쪽으로 가세요.`, pl: `Proszę skręcić w prawo.`},{who: `you`, ko: `역 이름이 뭐예요?`, pl: `Jaka jest nazwa stacji?`},{who: `them`, ko: `안국역이에요.`, pl: `To stacja Anguk.`},{who: `you`, ko: `정말 감사합니다.`, pl: `Bardzo dziękuję.`},{who: `them`, ko: `괜찮아요. 좋은 여행 되세요.`, pl: `Nie ma sprawy. Miłej podróży.`}]},{id: 4, title: `W tradycyjnej restauracji`, scene: `Wchodzisz do małej restauracji w Jeonju, znanej z bibimbapu. Chcesz stolik dla dwóch osób, pytasz o ostrość dania i płacisz kartą.`, lines: [{who: `them`, ko: `어서 오세요. 몇 명이에요?`, pl: `Witamy. Ile osób?`},{who: `you`, ko: `두 명이에요.`, pl: `Dwie osoby.`},{who: `them`, ko: `여기 앉으세요.`, pl: `Proszę usiąść tutaj.`},{who: `you`, ko: `메뉴판 주세요.`, pl: `Proszę kartę menu.`},{who: `them`, ko: `여기 있습니다. 비빔밥이 유명해요.`, pl: `Oto ona. Bibimbap jest słynny.`},{who: `you`, ko: `비빔밥 두 개 주세요.`, pl: `Poproszę dwa bibimbapy.`},{who: `them`, ko: `매운 거 괜찮으세요?`, pl: `Czy ostre jedzenie jest w porządku?`},{who: `you`, ko: `조금만 맵게 해 주세요.`, pl: `Proszę tylko trochę ostre.`},{who: `them`, ko: `네, 알겠습니다.`, pl: `Dobrze, rozumiem.`},{who: `you`, ko: `물도 주세요.`, pl: `Proszę też wodę.`},{who: `them`, ko: `맛있게 드세요.`, pl: `Smacznego.`},{who: `you`, ko: `감사합니다. 나중에 카드로 결제할게요.`, pl: `Dziękuję. Później zapłacę kartą.`}]},{id: 5, title: `Kupowanie biletu na pociąg`, scene: `Jesteś na dworcu Seoul Station i chcesz kupić bilet KTX do Busanu. Pytasz o miejsce, godzinę odjazdu i bilet w jedną stronę.`, lines: [{who: `them`, ko: `안녕하세요, 어디 가세요?`, pl: `Dzień dobry, dokąd pan/pani jedzie?`},{who: `you`, ko: `부산 가는 표 주세요.`, pl: `Proszę bilet do Busanu.`},{who: `them`, ko: `편도예요, 왕복이에요?`, pl: `W jedną stronę czy w obie?`},{who: `you`, ko: `편도예요.`, pl: `W jedną stronę.`},{who: `them`, ko: `오늘 표를 원하세요?`, pl: `Czy chce pan/pani bilet na dzisiaj?`},{who: `you`, ko: `네, 오늘 가요.`, pl: `Tak, jadę dzisiaj.`},{who: `them`, ko: `오후 두 시 KTX 좌석 있어요.`, pl: `Są miejsca w KTX o drugiej po południu.`},{who: `you`, ko: `몇 시에 도착해요?`, pl: `O której przyjeżdża?`},{who: `them`, ko: `오후 네 시 반에 도착해요.`, pl: `Przyjeżdża o czwartej trzydzieści po południu.`},{who: `you`, ko: `좋아요. 이걸로 할게요.`, pl: `Dobrze. Wezmę to.`},{who: `them`, ko: `카드로 결제하세요?`, pl: `Czy płaci pan/pani kartą?`},{who: `you`, ko: `네, 카드로 결제할게요.`, pl: `Tak, zapłacę kartą.`}]},{id: 6, title: `Zakupy na targu`, scene: `Jesteś na targu Namdaemun i oglądasz pamiątki. Pytasz o cenę, inny kolor i prosisz o zapakowanie na prezent.`, lines: [{who: `them`, ko: `어서 오세요. 구경하세요.`, pl: `Witamy. Proszę oglądać.`},{who: `you`, ko: `이거 얼마예요?`, pl: `Ile to kosztuje?`},{who: `them`, ko: `만 오천 원이에요.`, pl: `Piętnaście tysięcy wonów.`},{who: `you`, ko: `다른 색 있어요?`, pl: `Czy jest inny kolor?`},{who: `them`, ko: `네, 파란색하고 빨간색 있어요.`, pl: `Tak, jest niebieski i czerwony.`},{who: `you`, ko: `파란색 주세요.`, pl: `Proszę niebieski.`},{who: `them`, ko: `선물이에요?`, pl: `Czy to prezent?`},{who: `you`, ko: `네, 선물 포장해 주세요.`, pl: `Tak, proszę zapakować na prezent.`},{who: `them`, ko: `알겠습니다. 봉투 필요하세요?`, pl: `Rozumiem. Czy potrzebna torba?`},{who: `you`, ko: `네, 봉투도 주세요.`, pl: `Tak, proszę też torbę.`},{who: `them`, ko: `총 만 오천 원입니다.`, pl: `Razem piętnaście tysięcy wonów.`},{who: `you`, ko: `여기 있습니다. 감사합니다.`, pl: `Proszę bardzo. Dziękuję.`}]},{id: 7, title: `W aptece`, scene: `Po całym dniu zwiedzania boli cię głowa i idziesz do apteki w Hongdae. Wyjaśniasz objawy i pytasz, jak często brać lek.`, lines: [{who: `them`, ko: `안녕하세요, 어디가 아프세요?`, pl: `Dzień dobry, co pana/panią boli?`},{who: `you`, ko: `머리가 아파요.`, pl: `Boli mnie głowa.`},{who: `them`, ko: `열도 있어요?`, pl: `Czy ma pan/pani też gorączkę?`},{who: `you`, ko: `아니요, 열은 없어요.`, pl: `Nie, nie mam gorączki.`},{who: `them`, ko: `이 약을 드세요.`, pl: `Proszę wziąć ten lek.`},{who: `you`, ko: `처방전이 필요해요?`, pl: `Czy potrzebna jest recepta?`},{who: `them`, ko: `아니요, 필요 없어요.`, pl: `Nie, nie jest potrzebna.`},{who: `you`, ko: `하루에 몇 번 먹어요?`, pl: `Ile razy dziennie brać?`},{who: `them`, ko: `하루에 두 번 드세요.`, pl: `Proszę brać dwa razy dziennie.`},{who: `you`, ko: `물이랑 먹어요?`, pl: `Brać z wodą?`},{who: `them`, ko: `네, 물이랑 드세요.`, pl: `Tak, proszę brać z wodą.`},{who: `you`, ko: `감사합니다.`, pl: `Dziękuję.`}]},{id: 8, title: `Krótka rozmowa z lokalną osobą`, scene: `Siedzisz w małej kawiarni w Busanie i lokalna osoba zaczyna rozmowę po tym, jak słyszy twój koreański. Rozmawiacie o podróży, jedzeniu i Polsce.`, lines: [{who: `you`, ko: `안녕하세요, 여기 자리 있어요?`, pl: `Dzień dobry, czy to miejsce jest wolne?`},{who: `them`, ko: `네, 앉으세요. 한국어 잘하시네요.`, pl: `Tak, proszę usiąść. Dobrze mówi pan/pani po koreańsku.`},{who: `you`, ko: `감사합니다. 한국어를 조금 해요.`, pl: `Dziękuję. Mówię trochę po koreańsku.`},{who: `them`, ko: `어디에서 왔어요?`, pl: `Skąd pan/pani jest?`},{who: `you`, ko: `폴란드에서 왔어요.`, pl: `Jestem z Polski.`},{who: `them`, ko: `한국 여행은 어때요?`, pl: `Jak podróż po Korei?`},{who: `you`, ko: `정말 좋아요. 음식도 맛있어요.`, pl: `Bardzo mi się podoba. Jedzenie też jest smaczne.`},{who: `them`, ko: `어떤 음식을 좋아해요?`, pl: `Jakie jedzenie pan/pani lubi?`},{who: `you`, ko: `비빔밥하고 김치를 좋아해요.`, pl: `Lubię bibimbap i kimchi.`},{who: `them`, ko: `부산도 마음에 들어요?`, pl: `Czy Busan też się podoba?`},{who: `you`, ko: `네, 바다와 카페가 좋아요.`, pl: `Tak, podoba mi się morze i kawiarnie.`},{who: `them`, ko: `좋은 여행 되세요.`, pl: `Miłej podróży.`}]}];